{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier context. A user requests to cancel a previously placed delivery order. The feasibility and consequences of cancellation depend heavily on the order's current lifecycle state — cancellation after physical pickup has fundamentally different cost and operational implications than cancellation moments after placement.",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a user to have a package picked up from an origin and delivered to a destination, tracked through a defined lifecycle." },
      { "term": "Cancellation", "definition": "A user-initiated request to terminate an active order before final delivery. May or may not be honourable depending on order state." },
      { "term": "Order State", "definition": "The current phase in the order lifecycle (e.g., Placed, Confirmed, Assigned, PickedUp, InTransit, OutForDelivery, Delivered, Cancelled, Failed)." },
      { "term": "Point of No Return", "definition": "The order state beyond which user-initiated cancellation is no longer permitted (typically once the package is physically in transit or out for delivery)." },
      { "term": "Cancellation Fee", "definition": "A charge applied to the user when cancellation occurs after resources (courier time, vehicle dispatch) have already been committed." },
      { "term": "Refund", "definition": "The return of payment to the user upon successful cancellation, which may be full or partial depending on when cancellation occurs." },
      { "term": "Courier", "definition": "The person or agent assigned to physically pick up and deliver the package." },
      { "term": "Cancellation Window", "definition": "The set of order states during which cancellation is permitted." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Only the user who placed the order (the order owner) may initiate cancellation of that order.",
      "invariant": true,
      "invariant_justification": "Allowing a non-owner to cancel another user's order is an authorization violation that corrupts system integrity.",
      "testable_assertion": "Given user A placed order X, when user B attempts to cancel order X, then the system rejects the request with an authorization error."
    },
    {
      "id": "BR-2",
      "rule": "An order may only be cancelled if its current state is within the cancellation window (Placed, Confirmed, or Assigned). Orders in states PickedUp, InTransit, OutForDelivery, Delivered, Failed, or already Cancelled cannot be cancelled by the user.",
      "invariant": true,
      "invariant_justification": "Once a package is physically in the courier's possession, unilateral user cancellation would create an orphaned physical package with no delivery instructions — a corrupt operational state.",
      "testable_assertion": "Given an order in state PickedUp, when the user requests cancellation, then the system rejects the request and returns an error indicating the order is past the point of no return."
    },
    {
      "id": "BR-3",
      "rule": "A cancelled order must transition to the terminal state 'Cancelled' and no further state transitions are permitted.",
      "invariant": true,
      "invariant_justification": "Allowing a cancelled order to transition to Assigned or InTransit would mean dispatching a courier for a cancelled job — a data integrity violation.",
      "testable_assertion": "Given an order in state Cancelled, when any state transition is attempted, then the system rejects it."
    },
    {
      "id": "BR-4",
      "rule": "Cancellation of an order in state 'Placed' or 'Confirmed' (before courier assignment) results in a full refund with no cancellation fee.",
      "invariant": false,
      "invariant_justification": "Refund policy is a business decision that could be changed by leadership. The percentage and fee structure are policy, not physics.",
      "testable_assertion": "Given an order in state Placed, when the user cancels, then a full refund is issued and no cancellation fee is charged."
    },
    {
      "id": "BR-5",
      "rule": "Cancellation of an order in state 'Assigned' (courier dispatched but package not yet picked up) may incur a cancellation fee to compensate for committed courier resources.",
      "invariant": false,
      "invariant_justification": "The fee amount and whether to charge at all is a business policy decision, not a system integrity constraint.",
      "testable_assertion": "Given an order in state Assigned, when the user cancels, then the system applies the configured cancellation fee and issues a partial refund for the remainder."
    },
    {
      "id": "BR-6",
      "rule": "When an assigned order is cancelled, the assigned courier must be notified immediately and unassigned from the order.",
      "invariant": true,
      "invariant_justification": "Failing to notify the courier means they continue toward a pickup that no longer exists, wasting real-world resources and creating an inconsistent system state.",
      "testable_assertion": "Given an order in state Assigned with courier C, when the user cancels, then courier C receives a cancellation notification and is unassigned from the order."
    },
    {
      "id": "BR-7",
      "rule": "A cancellation event must be recorded in the order's audit trail with timestamp, initiator, reason (if provided), previous state, and refund/fee details.",
      "invariant": true,
      "invariant_justification": "Without an audit trail, financial disputes and operational investigations cannot be resolved — this is a data integrity and compliance requirement.",
      "testable_assertion": "Given any successful cancellation, when the audit trail is queried, then it contains the cancellation event with all required fields populated."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A user has an order in state 'Placed'",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to 'Cancelled', a full refund is issued, and a cancellation event is recorded in the audit trail"
    },
    {
      "id": "AC-2",
      "given": "A user has an order in state 'Confirmed'",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to 'Cancelled', a full refund is issued, and a cancellation event is recorded in the audit trail"
    },
    {
      "id": "AC-3",
      "given": "A user has an order in state 'Assigned' with a courier dispatched",
      "when": "The user requests cancellation of that order",
      "then": "The order transitions to 'Cancelled', the courier is notified and unassigned, any applicable cancellation fee is applied, the remaining amount is refunded, and the event is audited"
    },
    {
      "id": "AC-4",
      "given": "A user has an order in state 'PickedUp', 'InTransit', or 'OutForDelivery'",
      "when": "The user requests cancellation",
      "then": "The system rejects the request with a clear error message explaining the order is past the cancellable stage, and the order state remains unchanged"
    },
    {
      "id": "AC-5",
      "given": "A user has an order in state 'Delivered'",
      "when": "The user requests cancellation",
      "then": "The system rejects the request with an error indicating the order is already completed, and directs the user to the returns/dispute process instead"
    },
    {
      "id": "AC-6",
      "given": "A user has an order already in state 'Cancelled'",
      "when": "The user requests cancellation again",
      "then": "The system returns an idempotent success or informational response indicating the order is already cancelled, without creating duplicate refunds or audit entries"
    },
    {
      "id": "AC-7",
      "given": "User A attempts to cancel an order placed by User B",
      "when": "The cancellation request is submitted",
      "then": "The system rejects the request with an authorization error and does not reveal order details of User B"
    },
    {
      "id": "AC-8",
      "given": "A user requests cancellation of an order in state 'Assigned'",
      "when": "The courier notification fails to deliver",
      "then": "The cancellation still succeeds for the user, the courier notification is retried asynchronously, and the failure is logged for operational follow-up"
    },
    {
      "id": "AC-9",
      "given": "A user requests cancellation of an order that is transitioning states concurrently (e.g., being picked up at the same moment)",
      "when": "The cancellation and the pickup race",
      "then": "Exactly one operation wins: either the order is cancelled OR it advances to PickedUp — never both. The losing operation receives an appropriate error."
    },
    {
      "id": "AC-10",
      "given": "A user requests cancellation and provides an optional reason",
      "when": "The cancellation is processed",
      "then": "The reason is stored in the audit trail and available for analytics, but providing a reason is not required to complete cancellation"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Race condition: courier picks up package at the exact moment user cancels",
      "expected_behavior": "The system must use optimistic locking or state guards so that exactly one operation succeeds. If the pickup wins, cancellation is rejected with a 'past point of no return' error. If cancellation wins, the courier is notified to abort and return/not pick up the package."
    },
    {
      "scenario": "Double cancellation: user clicks cancel twice rapidly",
      "expected_behavior": "The operation is idempotent. The first request cancels the order; the second returns a success/informational response without issuing a duplicate refund or creating a duplicate audit entry."
    },
    {
      "scenario": "Payment provider is down when refund is attempted",
      "expected_behavior": "The order still transitions to Cancelled (the domain truth), and the refund is queued for retry. The user is informed that cancellation succeeded and refund is being processed. A failed refund must not block the state transition."
    },
    {
      "scenario": "Order is in 'Assigned' state but the courier has not yet acknowledged the assignment",
      "expected_behavior": "Cancellation proceeds as normal for Assigned state. The courier notification system handles the case where the courier never acknowledged — the assignment is simply voided."
    },
    {
      "scenario": "User cancels an order that was placed with a promotional discount or voucher",
      "expected_behavior": "The refund restores the original payment method amount. Voucher/promo reinstatement is governed by promotion policy (not guaranteed) and must be clearly communicated to the user."
    },
    {
      "scenario": "Cancellation requested for an order with multiple packages or legs",
      "expected_behavior": "Cancellation applies to the entire order atomically. Partial cancellation (one package out of many) is a different operation and should not be conflated with order cancellation."
    },
    {
      "scenario": "User's account is suspended or flagged for abuse after placing the order but before cancelling",
      "expected_behavior": "A suspended user should still be able to cancel their own orders (it reduces operational burden). However, the refund destination and method may be subject to fraud review."
    },
    {
      "scenario": "Network timeout during cancellation — user doesn't know if it succeeded",
      "expected_behavior": "The cancellation endpoint must be idempotent so the user can safely retry. The UI should allow the user to check current order state."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly affects revenue (refunds reduce realized revenue), courier compensation (fees for wasted dispatch time), and potential abuse (serial cancellers gaming promotions). A cancellation fee for post-assignment orders partially offsets courier costs. Refund processing costs are also a factor.",
    "operational": "Correct cancellation prevents wasted courier dispatches, reduces failed delivery attempts, and keeps operational dashboards accurate. Poor cancellation handling (e.g., courier not notified) creates phantom deliveries that waste fleet capacity.",
    "user": "Users expect cancellation to be easy, fast, and clearly communicated. The ability to cancel builds trust and reduces support tickets. However, the point-of-no-return must be clearly surfaced in the UI to prevent frustration when cancellation is denied.",
    "risk": "Key risks include: (1) refund fraud via repeated cancel/re-order cycles to exploit promotions, (2) race conditions causing inconsistent state between order and courier systems, (3) missing audit trail creating disputes that cannot be resolved, (4) courier notification failures causing real-world waste.",
    "stakeholders_affected": [
      { "group": "End Users (Senders)", "impact": "Gain self-service cancellation capability, reducing need to contact support. Must understand the cancellation window to avoid frustration." },
      { "group": "Couriers", "impact": "Must receive timely cancellation notifications to avoid wasted trips. Assigned-state cancellations directly affect their earnings and route efficiency." },
      { "group": "Customer Support", "impact": "Reduced ticket volume for cancellation requests. Must handle edge cases (past-point-of-no-return requests, refund disputes) that self-service cannot cover." },
      { "group": "Finance / Accounting", "impact": "Must reconcile refunds and cancellation fees. Audit trail is critical for dispute resolution and financial reporting." },
      { "group": "Product / Analytics", "impact": "Cancellation reasons provide signal on service quality, pricing issues, or UX friction. High cancellation rates may indicate upstream problems." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec is a single sentence with no detail on order states, refund policy, cancellation fees, or lifecycle definition. All business rules above are inferred from standard logistics domain knowledge, not from an actual specification. The order state names, fee structures, refund policies, and point-of-no-return definition are all assumptions that require PM/stakeholder confirmation.",
    "high_confidence_areas": [
      "Order cancellation must respect lifecycle state — physical constraints make this universal",
      "Only order owners can cancel their own orders — fundamental authorization rule",
      "Cancelled is a terminal state — universal state machine invariant",
      "Courier must be notified on assignment-stage cancellation — operational necessity",
      "Audit trail is required — standard compliance and dispute resolution need"
    ],
    "low_confidence_areas": [
      "Exact order states and their names in this specific system",
      "Cancellation fee amount and whether it exists at all",
      "Refund policy details (full vs partial, timing)",
      "Whether 'Assigned' state allows cancellation or is already past the point of no return",
      "Voucher/promotion reinstatement policy",
      "Whether partial order cancellation is in scope"
    ],
    "assumptions": [
      "The system has a defined order lifecycle with distinguishable states",
      "Payment has been collected at order placement (pre-paid model)",
      "Couriers are assigned to individual orders (not batch routes)",
      "The cancellation window ends at physical pickup, not at courier assignment",
      "Cancellation is all-or-nothing per order (no partial cancellation)"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order states are cancellable. The 'point of no return' — whether cancellation is blocked at courier assignment, at pickup, or at some other state — is the single most important business decision for this feature and is unspecified.",
      "affected_stakeholders": ["End Users", "Couriers", "Customer Support", "Finance"],
      "options": [
        "A) Allow cancellation up to and including 'Assigned' state (courier dispatched but not yet picked up)",
        "B) Allow cancellation only before courier assignment ('Placed' and 'Confirmed' states)",
        "C) Allow cancellation at any state before 'Delivered' but with escalating fees"
      ],
      "recommendation": "Option A — allows maximum user flexibility while respecting the physical constraint that once a package is picked up, cancellation creates an orphaned package problem."
    },
    {
      "type": "ambiguity",
      "description": "No refund or cancellation fee policy is specified. Should there be a fee for late cancellations (e.g., after courier dispatch)? What is the refund method and timeline?",
      "affected_stakeholders": ["End Users", "Finance", "Customer Support"],
      "options": [
        "A) Full refund always, no cancellation fee regardless of state",
        "B) Full refund before assignment, partial refund (minus cancellation fee) after assignment",
        "C) Configurable fee schedule based on state and time elapsed"
      ],
      "recommendation": "Option B — balances user friendliness with fair compensation for committed courier resources."
    },
    {
      "type": "missing_context",
      "description": "The actual order lifecycle states in this system are unknown. The states used in this analysis (Placed, Confirmed, Assigned, PickedUp, InTransit, OutForDelivery, Delivered, Cancelled, Failed) are assumed from standard logistics patterns but may not match the codebase.",
      "affected_stakeholders": ["Engineering", "Product"],
      "options": [
        "Provide the actual order state machine from the codebase or domain model",
        "Confirm the assumed states are acceptable"
      ],
      "recommendation": "Share the existing order entity/enum definitions so acceptance criteria can reference actual states."
    }
  ],

  "rejection_reasons": []
}

